std::vector<ComplexVector> compute_coeffs_scalar(const HighPrecisionScalar a, const HighPrecisionScalar M, const HighPrecisionScalar lambda, const HighPrecisionVector &r) {
std::vector<HighPrecisionVector> expr(4);
std::vector<ComplexVector> coeffs(6);
expr[0] = sqrt((pow(a,2))+((r)*(((-2)*(M))+(r))));
expr[1] = sqrt((pow(r,3))+((pow(a,2))*(((2)*(M))+(r))));
expr[2] = sqrt(r);
expr[3] = atan((a)*((pow((pow(r,4))+((pow(a,2))*((r)*(((2)*(M))+(r)))),-1))*((expr[0])*((expr[1])*(expr[2])))));

 typedef void (*ComputeCoeffFunctionPointer)(const HighPrecisionScalar a, const HighPrecisionScalar M, const HighPrecisionScalar lambda, const HighPrecisionVector &r, const std::vector<HighPrecisionVector> &expr, std::vector<ComplexVector> &coeffs);
 std::vector<ComputeCoeffFunctionPointer> pointers = {compute_coeffs_scalar_0, compute_coeffs_scalar_1, compute_coeffs_scalar_2, compute_coeffs_scalar_3, compute_coeffs_scalar_4, compute_coeffs_scalar_5};

 boost::lockfree::queue<int> q(10);
 for(size_t i = 0; i < coeffs.size(); i++){
   q.push(i);
 }
 
 size_t num_threads = std::thread::hardware_concurrency() / 2;
 auto threads = std::vector<std::thread>(0);
 for(size_t i = 0; i < num_threads; ++i){
   threads.push_back(std::thread([&](void){
     size_t idx;
     while(q.pop(idx)){
       pointers[idx](a, M, lambda, r, expr, coeffs);
     }
   }));
 }

 for(size_t i = 0; i < num_threads; ++i){
   if(threads[i].joinable()){
     threads[i].join();
   }
 }

return coeffs;
}


  void prepare_coeffs_scalar(std::vector<ComplexVector> &coeffs, const Scalar rast_min, const Scalar rast_max, const long long int N, const Scalar M, const Scalar lambda, const Scalar a) {
    auto a_hp = static_cast<HighPrecisionScalar>(a);
    auto M_hp = static_cast<HighPrecisionScalar>(M);
    auto lambda_hp = static_cast<HighPrecisionScalar>(lambda);
    auto rast_min_hp = static_cast<HighPrecisionScalar>(rast_min);
    auto rast_max_hp = static_cast<HighPrecisionScalar>(rast_max);

    
    std::vector<ComplexVector> coeffs_temp;
    
    // Try loading coeffs from file
    const std::string filename = Asset::to_hashed_filename("coeffs", rast_min, rast_max, N, M, lambda, a);
    
    auto loaded = read_from_file<ComplexVector>(filename);
    if(loaded.has_value()) {
      const size_t num_segments = loaded->size() / (N+1);
      coeffs_temp.resize(num_segments);
      for(size_t i = 0; i < num_segments; ++i) {
	coeffs_temp[i] = (*loaded)(Eigen::seqN((N+1)*i, N+1));
      }
    } else {
      const std::string r_hp_filename = Asset::to_hashed_filename("r_hp", rast_min, rast_max, N, M, a);
      auto r_hp_loaded = read_from_file<Teukolsky::HighPrecisionVector>(r_hp_filename);
      Teukolsky::HighPrecisionVector r_hp;
      if(r_hp_loaded.has_value()){
	r_hp = *r_hp_loaded;
      } else {
	r_hp = compute_hp_r_vector(rast_min_hp, rast_max_hp, N, M_hp, a_hp);
	write_to_file(r_hp, r_hp_filename);
      }

      coeffs_temp = compute_coeffs_scalar(a_hp, M_hp, lambda_hp, r_hp);
      ComplexVector to_save(coeffs_temp.size() * (N+1));
      for(size_t i = 0; i < coeffs_temp.size(); ++i) {
	to_save(Eigen::seqN((N+1)*i, N+1)) = coeffs_temp[i];
      }
      write_to_file(to_save, filename);
    }

    // Commit coeffs
    coeffs.resize(coeffs_temp.size());
    for(size_t i = 0; i < coeffs.size(); ++i) {
      // Don't change this to coeffs[i].swap(coeffs_temp[i])!
      // Copying the contents is a workaround for compatibility between .cpp and .cu binaries
      coeffs[i] = coeffs_temp[i];
    }

 
  }


